const data = $input.first().json;
const bookings = Array.isArray(data) ? data : (data?.get_tomorrow_bookings || []);

if (!bookings || bookings.length === 0) {
  return [{ json: {
    status: 'completed',
    workflow: '01_clients_lesson_reminder',
    message: 'No bookings found for tomorrow',
    reminders: [],
    count: 0
  } }];
}

return bookings.map(b => ({ json: {
  bookingId: b.id,
  parentName: b.parent_name || 'Parent',
  parentPhone: b.parent_phone || '',
  coachName: b.coach_name || 'Coach',
  studentName: b.student_name || 'Student',
  poolName: b.pool_name || 'TBD',
  poolAddress: b.pool_address || '',
  lessonTime: b.lesson_time || 'TBD',
  lessonFee: b.lesson_fee,
  currency: b.currency || 'AED'
} }));

const items = $input.all();
const bookingData = $('Parse Bookings').all();

const reminders = items.map((item, i) => {
  const booking = bookingData[i]?.json || {};
  const message = item.json?.content?.[0]?.text || 'Reminder: swimming lesson tomorrow!';
  return {
    parent: booking.parentName,
    student: booking.studentName,
    phone: booking.parentPhone,
    coach: booking.coachName,
    pool: booking.poolName,
    time: booking.lessonTime,
    message
  };
});

return [{ json: {
  status: 'completed',
  workflow: '01_clients_lesson_reminder',
  reminders_generated: reminders.length,
  reminders,
  completedAt: new Date().toISOString()
} }];
